// خلط مصفوفة (نسخة جديدة) — Fisher–Yates
function shuffled(arr) {
  const a = arr.slice()
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[a[i], a[j]] = [a[j], a[i]]
  }
  return a
}

// ——— نظام «المجموعة» (deck): يمرّ على كل البنك مرة كاملة قبل أي تكرار، ثم يُعاد الخلط (لوب) ———
// المجموعة محفوظة في localStorage لكل لعبة على حدة (مفتاح مستقل)، وتُبنى على جهاز واحد
// (المُتحكّم الذي يستدعي pickQuestions داخل الـ commit)، فتبقى متسقة لجميع اللاعبين.
const DECK_PREFIX = 'anasah:qdeck:'

function loadDeck(key) {
  try { return JSON.parse(localStorage.getItem(DECK_PREFIX + key)) } catch { return null }
}
function saveDeck(key, deck, cursor) {
  try { localStorage.setItem(DECK_PREFIX + key, JSON.stringify({ deck, cursor })) } catch { /* تجاهل */ }
}

// يسحب n فهارس بلا تكرار حتى تنتهي كل الأسئلة، ثم يُعيد الخلط ويلفّ من جديد.
// key: مفتاح مستقل لكل لعبة (مثل 'trivia' أو 'blindbet').
export function pickQuestions(n, key = 'default') {
  const total = QUESTIONS.length
  n = Math.min(n, total)

  const saved = loadDeck(key)
  let deck = Array.isArray(saved?.deck) ? saved.deck.filter((i) => i >= 0 && i < total) : null
  let cursor = Number.isInteger(saved?.cursor) ? saved.cursor : 0

  if (!deck || deck.length === 0) {
    // لا توجد مجموعة → ابنِ مجموعة مخلوطة لكل البنك
    deck = shuffled(QUESTIONS.map((_, i) => i))
    cursor = 0
  } else if (deck.length < total) {
    // كبُر البنك (أُضيفت أسئلة) → ادمج الجديد ضمن المتبقّي دون المساس بما عُرض
    const served = deck.slice(0, cursor)
    const known = new Set(deck)
    const fresh = []
    for (let i = 0; i < total; i++) if (!known.has(i)) fresh.push(i)
    deck = served.concat(shuffled(deck.slice(cursor).concat(fresh)))
  }
  if (cursor > deck.length) cursor = deck.length

  const result = []
  while (result.length < n) {
    if (cursor >= deck.length) {
      // انتهت المجموعة → أعِد الخلط، مع إبعاد ما سُحب للتوّ عن بداية المجموعة الجديدة
      const drawn = new Set(result)
      const re = shuffled(deck)
      deck = re.filter((i) => !drawn.has(i)).concat(re.filter((i) => drawn.has(i)))
      cursor = 0
    }
    result.push(deck[cursor])
    cursor++
  }

  saveDeck(key, deck, cursor)
  return result
}
